import{_ as e,o as a,c as i,ae as r}from"./chunks/framework.D_vkKrCz.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","sidebar":true,"hero":{"name":"IM2ODE","text":"逆向材料设计软件包","tagline":"Inverse Design of Materials by Multi-objective Differential Evolution","actions":[{"theme":"brand","text":"快速开始","link":"/guide/getting-started"},{"theme":"brand","text":"GitHub","link":"https://github.com/YueyuZhang/IM2ODE"}]},"features":[{"icon":"🧪","title":"多目标优化","details":"基于差分演化算法，同时优化多个材料属性，高效筛选最优结构"},{"icon":"💎","title":"多维度设计","details":"支持3D晶体、2D层状结构、1D纳米条带、0D团簇及复杂缺陷设计"},{"icon":"⚡","title":"高效可靠","details":"经过大量体系验证，搜索效率高，结果可靠，已被国内外众多科研团队采用"},{"icon":"📚","title":"丰富功能","details":"支持半导体带隙设计、超硬材料设计等多种功能材料逆向设计"}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),l={name:"index.md"};function d(o,t,n,s,h,u){return a(),i("div",null,[...t[0]||(t[0]=[r('<h2 id="什么是im2ode" tabindex="-1">什么是IM2ODE？ <a class="header-anchor" href="#什么是im2ode" aria-label="Permalink to &quot;什么是IM2ODE？&quot;">​</a></h2><p>IM²ODE (Inverse Design of Materials by Multi-Objective Differential Evolution) 是基于多目标差分演化算法的逆向材料设计软件包，由张越宇博士开发维护。</p><p>逆向材料设计是材料科学领域的前沿方向：从目标性能出发，通过理论计算直接预测满足需求的新材料结构，打破了传统“试错式”材料研发模式，大幅提升新材料发现效率。</p><p>经过十年持续开发与迭代，IM²ODE已经成为连接理论与实验的综合性材料设计平台：集成先进演化算法与第一性原理计算，能够预测块体、界面、团簇、复杂缺陷的稳定结构，支持光电、电子、力学等多目标性能同时优化，已在多个领域取得成功应用并得到实验验证。</p><h3 id="核心算法" tabindex="-1">核心算法 <a class="header-anchor" href="#核心算法" aria-label="Permalink to &quot;核心算法&quot;">​</a></h3><p>IM²ODE基于多目标差分演化算法，开源托管于GitHub，完整算法流程兼顾结构稳定性与多目标性能同时优化，搜索效率远超传统模拟退火、遗传算法等方法。</p><h3 id="十年发展历程" tabindex="-1">十年发展历程 <a class="header-anchor" href="#十年发展历程" aria-label="Permalink to &quot;十年发展历程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间</th><th>里程碑</th></tr></thead><tbody><tr><td>2013</td><td>项目启动，块体结构搜索模块上线</td></tr><tr><td>2014</td><td>实现准二维材料结构设计能力</td></tr><tr><td>2015</td><td>功能扩展到团簇与表面结构搜索</td></tr><tr><td>2016</td><td>新增晶界结构搜索模块</td></tr><tr><td>2018</td><td>集成复杂缺陷结构搜索能力</td></tr><tr><td>2013</td><td>新增纳米带结构搜索模块</td></tr><tr><td>2025</td><td>发布DFSE铁电材料专用搜索模块</td></tr></tbody></table><h2 id="主要应用领域" tabindex="-1">主要应用领域 <a class="header-anchor" href="#主要应用领域" aria-label="Permalink to &quot;主要应用领域&quot;">​</a></h2><h3 id="🎯-功能材料设计" tabindex="-1">🎯 功能材料设计 <a class="header-anchor" href="#🎯-功能材料设计" aria-label="Permalink to &quot;🎯 功能材料设计&quot;">​</a></h3><ul><li>特定能带带隙的半导体材料</li><li>超硬材料</li><li>光电功能材料</li><li>催化材料</li></ul><h3 id="📐-多维度材料支持" tabindex="-1">📐 多维度材料支持 <a class="header-anchor" href="#📐-多维度材料支持" aria-label="Permalink to &quot;📐 多维度材料支持&quot;">​</a></h3><ul><li><strong>3D</strong>：块体晶体结构</li><li><strong>2D</strong>：层状材料、表面与界面结构</li><li><strong>1D</strong>：纳米线、纳米条带结构</li><li><strong>0D</strong>：团簇、点缺陷、复杂缺陷结构</li></ul><h2 id="开源协议" tabindex="-1">开源协议 <a class="header-anchor" href="#开源协议" aria-label="Permalink to &quot;开源协议&quot;">​</a></h2><p>IM2ODE程序包在GNU General Public License (GPL) 下开源，许可社会公众享有：</p><ul><li>✅ 运行、复制软件的自由</li><li>✅ 发行传播软件的自由</li><li>✅ 获得软件源码的自由</li><li>✅ 改进软件并将自己作出的改进版本向社会发行传播的自由</li></ul>',16)])])}const m=e(l,[["render",d]]);export{b as __pageData,m as default};
